import { getMemberExpressionPropertyName, isGlobalIdentifierCall, isWindowSelfOrGlobalThisPropertyAccess, } from "../../utils/ast-utils.js";
describe('ast-utils', () => {
    describe('isGlobalIdentifierCall', () => {
        it('should return true for global identifier calls', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'Identifier',
                    name: 'fetch',
                },
                arguments: [],
                optional: false,
            };
            expect(isGlobalIdentifierCall(node, 'fetch')).toBe(true);
        });
        it('should return false when identifier name does not match', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'Identifier',
                    name: 'fetch',
                },
                arguments: [],
                optional: false,
            };
            expect(isGlobalIdentifierCall(node, 'XMLHttpRequest')).toBe(false);
        });
        it('should return false for member expression calls', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'window',
                    },
                    property: {
                        type: 'Identifier',
                        name: 'fetch',
                    },
                    computed: false,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isGlobalIdentifierCall(node, 'fetch')).toBe(false);
        });
    });
    describe('isWindowSelfOrGlobalThisPropertyAccess', () => {
        it('should return true for window.fetch with dot notation', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'window',
                    },
                    property: {
                        type: 'Identifier',
                        name: 'fetch',
                    },
                    computed: false,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(true);
        });
        it('should return true for globalThis.fetch with dot notation', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'globalThis',
                    },
                    property: {
                        type: 'Identifier',
                        name: 'fetch',
                    },
                    computed: false,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(true);
        });
        it('should return true for window["fetch"] with bracket notation', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'window',
                    },
                    property: {
                        type: 'Literal',
                        value: 'fetch',
                    },
                    computed: true,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(true);
        });
        it('should return true for globalThis["fetch"] with bracket notation', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'globalThis',
                    },
                    property: {
                        type: 'Literal',
                        value: 'fetch',
                    },
                    computed: true,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(true);
        });
        it('should return true for self.fetch with dot notation', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'self',
                    },
                    property: {
                        type: 'Identifier',
                        name: 'fetch',
                    },
                    computed: false,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(true);
        });
        it('should return true for self["fetch"] with bracket notation', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'self',
                    },
                    property: {
                        type: 'Literal',
                        value: 'fetch',
                    },
                    computed: true,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(true);
        });
        it('should return false when property name does not match', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'window',
                    },
                    property: {
                        type: 'Identifier',
                        name: 'alert',
                    },
                    computed: false,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(false);
        });
        it('should return false when object is not window or globalThis', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'MemberExpression',
                    object: {
                        type: 'Identifier',
                        name: 'document',
                    },
                    property: {
                        type: 'Identifier',
                        name: 'fetch',
                    },
                    computed: false,
                    optional: false,
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(false);
        });
        it('should return false for non-member expression calls', () => {
            const node = {
                type: 'CallExpression',
                callee: {
                    type: 'Identifier',
                    name: 'fetch',
                },
                arguments: [],
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'fetch')).toBe(false);
        });
        it('should return true for window access when a MemberExpression is passed directly', () => {
            const node = {
                type: 'MemberExpression',
                object: {
                    type: 'Identifier',
                    name: 'window',
                },
                property: {
                    type: 'Identifier',
                    name: 'document',
                },
                computed: false,
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'document')).toBe(true);
        });
        it('should return false for a directly passed MemberExpression when the object is not window, globalThis, or self', () => {
            const node = {
                type: 'MemberExpression',
                object: {
                    type: 'Identifier',
                    name: 'navigator',
                },
                property: {
                    type: 'Identifier',
                    name: 'document',
                },
                computed: false,
                optional: false,
            };
            expect(isWindowSelfOrGlobalThisPropertyAccess(node, 'document')).toBe(false);
        });
    });
    describe('getMemberExpressionPropertyName', () => {
        const createMemberExpression = (overrides) => {
            const { objectName = 'window', propertyName = 'method', propertyValue, computed = false, } = overrides || {};
            return {
                type: 'MemberExpression',
                object: { type: 'Identifier', name: objectName },
                property: propertyValue !== undefined
                    ? { type: 'Literal', value: propertyValue }
                    : { type: 'Identifier', name: propertyName },
                computed,
                optional: false,
            };
        };
        it('should extract property name from dot notation', () => {
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyName: 'alert' }))).toBe('alert');
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyName: 'confirm' }))).toBe('confirm');
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyName: 'prompt' }))).toBe('prompt');
        });
        it('should extract property name from bracket notation with string literal', () => {
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyValue: 'alert', computed: true }))).toBe('alert');
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyValue: 'fetch', computed: true }))).toBe('fetch');
        });
        it('should return undefined for bracket notation with non-string literals', () => {
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyValue: 123, computed: true }))).toBe(undefined);
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyValue: null, computed: true }))).toBe(undefined);
            expect(getMemberExpressionPropertyName(createMemberExpression({ propertyValue: true, computed: true }))).toBe(undefined);
        });
        it('should work with different object names', () => {
            expect(getMemberExpressionPropertyName(createMemberExpression({ objectName: 'window' }))).toBe('method');
            expect(getMemberExpressionPropertyName(createMemberExpression({ objectName: 'globalThis' }))).toBe('method');
            expect(getMemberExpressionPropertyName(createMemberExpression({ objectName: 'self' }))).toBe('method');
        });
    });
});
